import numpy as np

class DecisionTree:
    def __init__(self, max_depth=5, min_samples=2):
        self.max_depth = max_depth
        self.min_samples = min_samples

    def gini(self, y):
        classes, counts = np.unique(y, return_counts=True)
        probs = counts / len(y)
        return 1 - np.sum(probs**2)

    def best_split(self, X, y):
        best_gain, best_feat, best_thresh = 0, None, None
        parent_gini = self.gini(y)

        for feat in range(X.shape[1]):
            thresholds = np.unique(X[:, feat])
            for thresh in thresholds:
                left = y[X[:, feat] <= thresh]
                right = y[X[:, feat] > thresh]
                if len(left) == 0 or len(right) == 0:
                    continue
                gain = parent_gini - (len(left)/len(y))*self.gini(left) - (len(right)/len(y))*self.gini(right)
                if gain > best_gain:
                    best_gain, best_feat, best_thresh = gain, feat, thresh

        return best_feat, best_thresh

    def fit(self, X, y, depth=0):
        if depth >= self.max_depth or len(y) < self.min_samples or len(np.unique(y)) == 1:
            return {'leaf': True, 'class': np.bincount(y).argmax()}
        feat, thresh = self.best_split(X, y)
        if feat is None:
            return {'leaf': True, 'class': np.bincount(y).argmax()}
        left_mask = X[:, feat] <= thresh
        return {
            'leaf': False, 'feat': feat, 'thresh': thresh,
            'left': self.fit(X[left_mask], y[left_mask], depth+1),
            'right': self.fit(X[~left_mask], y[~left_mask], depth+1)
        }
